const p = $input.item.json;

// util
const num = (v, d = 0) => Number.isFinite(Number(v)) ? Number(v) : d;
const str = (v, d = '') => String(v ?? d);

// precios
const costo = num(p.precios?.precio_descuento ?? p.precio, 0);
const costoConIva = costo * 1.16;
const listPriceCalc = costo > 0 ? costoConIva / 0.7 : 0;

// categoría: toma la de mayor nivel; si no hay, default
let categoria_nombre = 'Syscom General';
let familia_nombre = '';
if (Array.isArray(p.categorias) && p.categorias.length) {
  const ordenadas = [...p.categorias].sort((a,b) => (a.nivel ?? 0) - (b.nivel ?? 0));
  categoria_nombre = ordenadas[0]?.nombre ?? 'Syscom General';
  familia_nombre = ordenadas[2]?.nombre ?? ordenadas[1]?.nombre ?? categoria_nombre;
}

const newItem = {
  // identificadores robustos
  barcode: str(p.producto_id ?? p.sku ?? p.modelo ?? ''),
  default_code: str(p.modelo ?? p.sku ?? p.producto_id ?? ''),
  name: str(p.titulo, 'Producto sin nombre'),

  // precios
  list_price: num(p.precios?.precio_especial, listPriceCalc),
  standard_price: costo,

  // otros campos con fallback
  categoria_nombre,
  familia_nombre,
  unidad_de_medida_nombre: str(p.unidad_de_medida?.nombre, 'Unidad(es)'),
  total_existencia: num(p.total_existencia, 0),
  sat_key: str(p.sat_key ?? p.clave_sat ?? null, ''),
  img_portada: str(p.img_portada, ''),
  marca: str(p.marca, ''),

  // metadatos
  producto_id_syscom: p.producto_id ?? null,
  property_account_income_id: 1,
  property_account_expense_id: 2,
};

return { json: newItem };

// Init Search Terms v9 - NO pre-guarda la página (evita avance fantasma en errores)
const CATS = ["Videovigilancia","Redes","Radiocomunicación","Automatización e Intrusión","Cableado Estructurado","Control de Acceso","Energía","Detección de Incendio","Sonido y Video","Herramientas"];
const PAGES_PER_RUN = 20;
const state = $getWorkflowStaticData('global');

// Avanzar categoría si el run anterior encontró página vacía
if (state._foundEmptyPage === true) {
    const prevCat = state.categoryIndex || 0;
    const nextCat = (prevCat + 1) % CATS.length;
    state.categoryIndex = nextCat;
    state.page = 1;
    state._foundEmptyPage = false;
    if (nextCat === 0) {
        state.lastCompletedCycle = new Date().toISOString();
        console.log('🏁 CATÁLOGO COMPLETO - reiniciando ciclo');
    } else {
        console.log('➡️  Cat[' + prevCat + '] → Cat[' + nextCat + '] ' + CATS[nextCat]);
    }
}

const catIdx = Math.max(0, Math.min(Number(state.categoryIndex) || 0, CATS.length - 1));
const startPage = Math.max(1, Number(state.page) || 1);

// Guardar referencia para que Guardar Estado sepa hasta dónde avanzar
state._startPage = startPage;
state._savedThisRun = false;

console.log('▶️  Cat[' + catIdx + '] "' + CATS[catIdx] + '" páginas ' + startPage + '–' + (startPage + PAGES_PER_RUN - 1));

const access_token = $('Get Syscom Token').first().json.access_token;
const items = [];
for (let p = startPage; p < startPage + PAGES_PER_RUN; p++) {
    items.push({ json: {
        page: p,
        access_token,
        categoria_actual: { nombre: CATS[catIdx] },
        categoria_actual_index: catIdx,
        categorias: CATS,
        productos_por_pagina: 20,
        start_page: startPage
    }});
}
return items;

// Process Pagination v10 - runOnceForAllItems, procesa todas las respuestas HTTP
const state = $getWorkflowStaticData('global');
const allHttpResponses = $input.all();           // 20 respuestas HTTP (una por página)
const allPageItems    = $('Init Search Terms').all(); // 20 items originales (page, cat, token)

const results = [];

for (let i = 0; i < allHttpResponses.length; i++) {
    const respuesta  = allHttpResponses[i].json;
    const pageItem   = allPageItems[i] ? allPageItems[i].json : allPageItems[0].json;
    const productos  = respuesta.productos || [];
    const pageNum    = pageItem.page;
    const catObj     = pageItem.categoria_actual;  // { nombre: '...' }
    const catIdx     = pageItem.categoria_actual_index;
    const token      = pageItem.access_token;

    if (productos.length === 0) {
        state._foundEmptyPage = true;
        console.log('⚠️  Pág vacía: ' + pageNum);
        continue;  // no agregar items al resultado
    }

    console.log('📥 Pág ' + pageNum + ': ' + productos.length + ' productos');
    for (const p of productos) {
        results.push({
            json: {
                ...p,
                categoria_actual: catObj,
                categoria_actual_index: catIdx,
                access_token: token,
                _pagina: pageNum
            }
        });
    }
}

if (results.length === 0) {
    console.log('⚠️  Todas las páginas vacías en este batch');
    // Retornar item dummy para que el flujo no colapse
    return [{ json: { _empty_batch: true, _pages: allHttpResponses.length } }];
}

console.log('✅ Total productos en batch: ' + results.length);
return results;

// Sin imagen — toma datos del item actual (Edit Fields)
const productData = $input.item.json;

const finalProduct = {
    name: productData.name,
    default_code: productData.default_code,
    barcode: productData.barcode,
    list_price: productData.list_price,
    standard_price: productData.standard_price,
    marca: productData.marca,
    categoria_nombre: productData.categoria_nombre,
    unidad_de_medida_nombre: productData.unidad_de_medida_nombre,
    total_existencia: productData.total_existencia,
    sat_key: productData.sat_key,
    producto_id_syscom: productData.producto_id_syscom,
    property_account_income_id: productData.property_account_income_id,
    property_account_expense_id: productData.property_account_expense_id,
    l10n_mx_edi_unspsc_code_id: productData.l10n_mx_edi_unspsc_code_id,
    image_1920: null
};

console.log('Producto sin imagen:', finalProduct.default_code);
return { json: finalProduct };

// Store Original State - Preserva TODO el estado original
// Este es el nodo más importante del flujo

return items.map((item, index) => {
    // Capturamos absolutamente TODO lo que viene de Syscom
    const syscomData = {
        // Identificadores principales
        barcode: item.json.barcode,
        default_code: item.json.default_code,
        name: item.json.name,

        // Información de precios
        list_price: item.json.list_price,
        standard_price: item.json.standard_price,

        // Categorización y clasificación
        categoria_nombre: item.json.categoria_nombre,
        familia_nombre: item.json.familia_nombre,
        unidad_de_medida_nombre: item.json.unidad_de_medida_nombre,

        // Inventario
        total_existencia: item.json.total_existencia,

        // Información fiscal
        sat_key: item.json.sat_key,

        // Multimedia
        img_portada: item.json.img_portada,

        // Marca y metadatos
        marca: item.json.marca,
        producto_id_syscom: item.json.producto_id_syscom,

        // Cuentas contables
        property_account_income_id: item.json.property_account_income_id,
        property_account_expense_id: item.json.property_account_expense_id
    };

    // Creamos una estructura que preservará todo durante el flujo
    const stateContainer = {
        // Los datos originales van en un contenedor protegido
        _original_syscom: syscomData,

        // Campo para el código SAT a buscar
        sat_key_to_search: item.json.sat_key,

        // Campo para el SKU a buscar en Odoo
        sku_to_search: item.json.default_code,

        // Metadata del procesamiento
        _processing: {
            timestamp: new Date().toISOString(),
            item_index: index,
            current_step: 'original_stored'
        },

        // Contenedor para resultados de búsquedas
        _search_results: {}
    };

    console.log(`✅ Estado original guardado para SKU: ${syscomData.default_code}`);
    console.log(`   Campos preservados: ${Object.keys(syscomData).length}`);

    return { json: stateContainer };
});

// Enrich with SAT — seguro contra null y formatos distintos
const item = $json;                 // item actual
const res  = item.result ?? item._search_results ?? null;

let sat_id = null;

if (res !== null && res !== undefined) {
  if (typeof res === 'number' || typeof res === 'string') {
    // La API devolvió el ID directo (p.ej. 43201803)
    sat_id = res;
  } else if (typeof res === 'object') {
    // La API devolvió objeto; prueba rutas posibles sin romper si son null
    const candidate =
      (res.sat_code ?? res.data?.sat_code ?? res.id ?? res.data?.id ?? null);

    if (candidate !== null && candidate !== undefined) {
      sat_id = (typeof candidate === 'object')
        ? (candidate?.id ?? null)
        : candidate;
    }
  }
}

// Fallbacks si no vino nada en result
if (!sat_id) sat_id = item.sat_key_to_search ?? item.sat_key ?? null;

console.log(
  `[SAT] default_code=${item.default_code || item._original_syscom?.default_code || 's/i'} -> sat_id=${sat_id ?? 'NONE'}`
);

return {
  json: {
    ...item,
    _search_results: res ?? null,
    sat_key: sat_id ?? null,
    sat_found: Boolean(sat_id),
  },
};

// Control de Lotes Mejorado
const items_procesados = [];
const TAMANO_LOTE = 15; // Reducido para servidor 2GB RAM // Procesar 60 productos a la vez

// Procesar items en lotes
for (let i = 0; i < items.length; i += TAMANO_LOTE) {
    const lote = items.slice(i, i + TAMANO_LOTE);
    const numeroLote = Math.floor(i / TAMANO_LOTE) + 1;

    console.log(`📦 Procesando lote ${numeroLote} con ${lote.length} productos`);

    // Agregar metadata a cada producto del lote
    const loteConMetadata = lote.map((item, indexEnLote) => ({
        json: {
            ...item.json,
            _batch_info: {
                lote_numero: numeroLote,
                posicion_en_lote: indexEnLote + 1,
                tamano_lote: lote.length,
                indice_global: i + indexEnLote + 1,
                total_items: items.length
            }
        }
    }));

    items_procesados.push(...loteConMetadata);

    // Log de progreso
    const porcentaje = ((i + lote.length) / items.length * 100).toFixed(1);
    console.log(`✅ Progreso: ${porcentaje}% completado`);
}

return items_procesados;

// Error Handler - Maneja errores sin detener todo el flujo
// Coloca este nodo para capturar errores de Update/Create

return items.map(item => {
    const producto = item.json;
    const error = item.error;

    // Si no hay error, el producto se procesó exitosamente
    if (!error) {
        console.log(`✅ Producto procesado: ${producto.default_code}`);
        return { 
            json: {
                ...producto,
                _status: 'success',
                _processed_at: new Date().toISOString()
            }
        };
    }

    // Si hay error, lo registramos pero no detenemos el flujo
    console.error(`❌ Error procesando ${producto.default_code}:`, error.message);

    // Determinar el tipo de error y si es recuperable
    const esErrorRecuperable = 
        error.message.includes('timeout') ||
        error.message.includes('ECONNRESET') ||
        error.message.includes('429');  // Rate limit

    // Registrar el error para análisis posterior
    const registroError = {
        ...producto,
        _status: 'error',
        _error: {
            mensaje: error.message,
            tipo: error.name,
            recuperable: esErrorRecuperable,
            timestamp: new Date().toISOString(),
            detalles_completos: error.stack
        },
        _batch_info: producto._batch_info,
        _retry_count: (producto._retry_count || 0) + 1
    };

    // Si es recuperable y no hemos excedido los reintentos, marcarlo para reintento
    if (esErrorRecuperable && registroError._retry_count <= 3) {
        console.log(`🔄 Marcando para reintento (intento ${registroError._retry_count}/3)`);
        registroError._status = 'pending_retry';
    }

    return { json: registroError };
});

// Error Handler - Maneja errores sin detener todo el flujo
// Coloca este nodo para capturar errores de Update/Create

return items.map(item => {
    const producto = item.json;
    const error = item.error;

    // Si no hay error, el producto se procesó exitosamente
    if (!error) {
        console.log(`✅ Producto procesado: ${producto.default_code}`);
        return { 
            json: {
                ...producto,
                _status: 'success',
                _processed_at: new Date().toISOString()
            }
        };
    }

    // Si hay error, lo registramos pero no detenemos el flujo
    console.error(`❌ Error procesando ${producto.default_code}:`, error.message);

    // Determinar el tipo de error y si es recuperable
    const esErrorRecuperable = 
        error.message.includes('timeout') ||
        error.message.includes('ECONNRESET') ||
        error.message.includes('429');  // Rate limit

    // Registrar el error para análisis posterior
    const registroError = {
        ...producto,
        _status: 'error',
        _error: {
            mensaje: error.message,
            tipo: error.name,
            recuperable: esErrorRecuperable,
            timestamp: new Date().toISOString(),
            detalles_completos: error.stack
        },
        _batch_info: producto._batch_info,
        _retry_count: (producto._retry_count || 0) + 1
    };

    // Si es recuperable y no hemos excedido los reintentos, marcarlo para reintento
    if (esErrorRecuperable && registroError._retry_count <= 3) {
        console.log(`🔄 Marcando para reintento (intento ${registroError._retry_count}/3)`);
        registroError._status = 'pending_retry';
    }

    return { json: registroError };
});

// Nodo: Process Summary
const estadisticas = {
    inicio: $('Init Search Terms').item.json.timestamp_inicio,
    fin: new Date().toISOString(),
    productos_procesados: 0,
    productos_creados: 0,
    productos_actualizados: 0,
    productos_con_error: 0,
    productos_con_imagen: 0,
    productos_sin_imagen: 0
};

// Contar resultados
items.forEach(item => {
    if (item.json._status === 'success') {
        estadisticas.productos_procesados++;
        if (item.json.operation === 'create') {
            estadisticas.productos_creados++;
        } else {
            estadisticas.productos_actualizados++;
        }
        if (item.json.has_image) {
            estadisticas.productos_con_imagen++;
        } else {
            estadisticas.productos_sin_imagen++;
        }
    } else if (item.json._status === 'error') {
        estadisticas.productos_con_error++;
    }
});

// Calcular tiempo transcurrido
const tiempoTotal = (new Date(estadisticas.fin) - new Date(estadisticas.inicio)) / 1000 / 60;
estadisticas.tiempo_minutos = tiempoTotal.toFixed(2);
estadisticas.productos_por_minuto = (estadisticas.productos_procesados / tiempoTotal).toFixed(1);

console.log("📊 RESUMEN DE PROCESAMIENTO:");
console.log(`✅ Procesados: ${estadisticas.productos_procesados}`);
console.log(`🆕 Creados: ${estadisticas.productos_creados}`);
console.log(`🔄 Actualizados: ${estadisticas.productos_actualizados}`);
console.log(`❌ Errores: ${estadisticas.productos_con_error}`);
console.log(`⏱️ Tiempo: ${estadisticas.tiempo_minutos} minutos`);
console.log(`⚡ Velocidad: ${estadisticas.productos_por_minuto} productos/minuto`);

return [{ json: estadisticas }];

// Normaliza el default_code del ÍTEM ACTUAL (sin clonar el 0)
const idx = $itemIndex;                          // índice del ítem actual
const mapItems   = $items("Map Syscom Odoo") || [];
const storeItems = $items("Store Original State") || [];

const fromMap   = mapItems[idx]?.json?.default_code;
const fromStore = storeItems[idx]?.json?._original_syscom?.default_code;

const dcode =
  $json.default_code ??
  fromMap ??
  fromStore ??
  "";

console.log(`[Code1] idx=${idx} default_code=${dcode}`);

return {
  json: {
    ...$json,
    default_code: String(dcode || "")
  }
};

// Incrementar Pagina - v3: memory-safe
const httpResp = $('HTTP Syscom Products').item.json;
const initState = $('Init Search Terms').first().json;
const globalState = $getWorkflowStaticData('global');

const currentPage = Number(httpResp.pagina) || 1;
const nextPage = currentPage + 1;

const pagesThisRun = (globalState._pagesThisRun || 0) + 1;
globalState._pagesThisRun = pagesThisRun;
const maxPages = initState.max_pages_per_run || 50;

console.log(`📄 Página ${currentPage} → ${nextPage} | Run: ${pagesThisRun}/${maxPages}`);

return [{
  json: {
    page: nextPage,
    access_token: $('Get Syscom Token').first().json.access_token,
    categoria_actual: initState.categoria_actual,
    categoria_actual_index: initState.categoria_actual_index ?? 0,
    categorias: initState.categorias,
    productos_por_pagina: 20,
    pages_this_run: pagesThisRun,
    max_pages_per_run: maxPages
  }
}];

const allCats = $('Init Search Terms').first().json.categorias;
const currentIdx = Number($input.item.json.categoria_actual_index) || 0;
const nextIdx = currentIdx + 1;
const access_token = $('Get Syscom Token').first().json.access_token;
const maxPages = $('Init Search Terms').first().json.max_pages_per_run || 50;

// Guardar estado en staticData
const state = $getWorkflowStaticData('global');

if (nextIdx >= allCats.length) {
    // Ciclo completo - resetear para próxima noche
    state.categoryIndex = 0;
    state.page = 1;
    state.lastCompletedCycle = new Date().toISOString();
    console.log(`🏁 Catálogo completo sincronizado. Próximo ciclo empezará desde el inicio.`);
    return [{ json: { _fin_catalogo: true, total_categorias: allCats.length } }];
}

// Avanzar a siguiente categoría
state.categoryIndex = nextIdx;
state.page = 1;
state.lastSave = new Date().toISOString();

console.log(`🔄 [${currentIdx}] ${allCats[currentIdx]?.nombre} → [${nextIdx}] ${allCats[nextIdx]?.nombre}`);

return [{ json: {
    _fin_catalogo: false,
    categoria_actual_index: nextIdx,
    categoria_actual: allCats[nextIdx],
    page: 1,
    access_token: access_token,
    productos_por_pagina: 20,
    pages_this_run: 0,
    max_pages_per_run: maxPages
}}];

// Guardar Estado v9 - AQUÍ se avanza la página (no en Init)
const state = $getWorkflowStaticData('global');
if (state._savedThisRun === true) {
    return [{ json: { logged: false }}];
}
state._savedThisRun = true;
const startPage = state._startPage || 1;
const PAGES_PER_RUN = 20;
state.page = startPage + PAGES_PER_RUN;
state.lastSave = new Date().toISOString();
console.log('💾 Guardado: cat[' + state.categoryIndex + '] → pág ' + state.page);
return [{ json: { logged: true, nextPage: state.page, categoryIndex: state.categoryIndex }}];

const p = $input.item.json;

// util
const num = (v, d = 0) => Number.isFinite(Number(v)) ? Number(v) : d;
const str = (v, d = '') => String(v ?? d);

// precios
const costo = num(p.precios?.precio_descuento ?? p.precio, 0);
const costoConIva = costo * 1.16;
const listPriceCalc = costo > 0 ? costoConIva / 0.7 : 0;

// categoría: toma la de mayor nivel; si no hay, default
let categoria_nombre = 'Syscom General';
let familia_nombre = '';
if (Array.isArray(p.categorias) && p.categorias.length) {
  const ordenadas = [...p.categorias].sort((a,b) => (a.nivel ?? 0) - (b.nivel ?? 0));
  categoria_nombre = ordenadas[0]?.nombre ?? 'Syscom General';
  familia_nombre = ordenadas[2]?.nombre ?? ordenadas[1]?.nombre ?? categoria_nombre;
}

const newItem = {
  // identificadores robustos
  barcode: str(p.producto_id ?? p.sku ?? p.modelo ?? ''),
  default_code: str(p.modelo ?? p.sku ?? p.producto_id ?? ''),
  name: str(p.titulo, 'Producto sin nombre'),

  // precios
  list_price: num(p.precios?.precio_especial, listPriceCalc),
  standard_price: costo,

  // otros campos con fallback
  categoria_nombre,
  familia_nombre,
  unidad_de_medida_nombre: str(p.unidad_de_medida?.nombre, 'Unidad(es)'),
  total_existencia: num(p.total_existencia, 0),
  sat_key: str(p.sat_key ?? p.clave_sat ?? null, ''),
  img_portada: str(p.img_portada, ''),
  marca: str(p.marca, ''),

  // metadatos
  producto_id_syscom: p.producto_id ?? null,
  property_account_income_id: 1,
  property_account_expense_id: 2,
};

return { json: newItem };

// Init Search Terms v9 - NO pre-guarda la página (evita avance fantasma en errores)
const CATS = ["Videovigilancia","Redes","Radiocomunicación","Automatización e Intrusión","Cableado Estructurado","Control de Acceso","Energía","Detección de Incendio","Sonido y Video","Herramientas"];
