// Enrich with SAT — seguro contra null y formatos distintos
const item = $json;                 // item actual
const res  = item.result ?? item._search_results ?? null;

let sat_id = null;

if (res !== null && res !== undefined) {
  if (typeof res === 'number' || typeof res === 'string') {
    // La API devolvió el ID directo (p.ej. 43201803)
    sat_id = res;
  } else if (typeof res === 'object') {
    // La API devolvió objeto; prueba rutas posibles sin romper si son null
    const candidate =
      (res.sat_code ?? res.data?.sat_code ?? res.id ?? res.data?.id ?? null);

    if (candidate !== null && candidate !== undefined) {
      sat_id = (typeof candidate === 'object')
        ? (candidate?.id ?? null)
        : candidate;
    }
  }
}

// Fallbacks si no vino nada en result
if (!sat_id) sat_id = item.sat_key_to_search ?? item.sat_key ?? null;

console.log(
  `[SAT] default_code=${item.default_code || item._original_syscom?.default_code || 's/i'} -> sat_id=${sat_id ?? 'NONE'}`
);

return {
  json: {
    ...item,
    _search_results: res ?? null,
    sat_key: sat_id ?? null,
    sat_found: Boolean(sat_id),
  },
};

